    {"name": "SW_Industry_Momentum", "description": "申万行业动量因子：基于申万行业分类的行业轮动", "formula": "cs_rank(industry_return_20d)", "category": "MOMENTUM", "sub_category": "CROSS_SECTIONAL_MOMENTUM", "direction": "POSITIVE", "source": "ShenWan_Industry"},
