    {"name": "SW_Industry_Rotation_Signal", "description": "申万行业轮动信号因子：行业轮动的择时信号", "formula": "industry_rotation_signal(momentum, valuation, sentiment)", "category": "MOMENTUM", "sub_category": "CROSS_SECTIONAL_MOMENTUM", "direction": "POSITIVE", "source": "ShenWan_Industry"},
